                        response = Response.FromValue(ApiManagementCertificateData.FromResponse(result), result);
                        break;
                    case 404:
                        response = Response.FromValue((ApiManagementCertificateData)null, result);
                        break;
                    default:
                        throw new RequestFailedException(result);
                }
                if (response.Value == null)
                {
                    return new NoValueResponse<WorkspaceCertificateResource>(response.GetRawResponse());
                }
                return Response.FromValue(new WorkspaceCertificateResource(Client, response.Value), response.GetRawResponse());
            }
            catch (Exception e)
            {
                scope.Failed(e);
                throw;
            }
        }

